module RefModule (
    input [19:0] in_data, // 5 numbers, each 4 bits
    output reg [19:0] out_data // 5 sorted numbers, each 4 bits
);
    integer obf_i, j;
    reg [3:0] arr [0:4];

    always @(*) begin
        // Load inputs into array
        for (obf_i = 0; obf_i < 5; obf_i = obf_i + 1) begin
            arr[obf_i] = in_data[(obf_i + 1) * 4 - 1 -: 4];
        end

        // Bubble sort logic
        for (obf_i = 0; obf_i < 5; obf_i = obf_i + 1) begin
            for (j = 0; j < 4 - obf_i; j = j + 1) begin
                if (arr[j] > arr[j + 1]) begin
                    // Swap
                    {arr[j], arr[j + 1]} = {arr[j + 1], arr[j]};
                end
            end
        end

        // Output sorted array
        for (obf_i = 0; obf_i < 5; obf_i = obf_i + 1) begin
            out_data[(obf_i + 1) * 4 - 1 -: 4] = arr[obf_i];
        end
    end
endmodule
